Check the package's `exports` and `main` fields. Ensure the referenced files actually exist (package may need to be built). In monorepos, ensure workspace links are set up.

Properly handle process termination signals to close connections, flush data, and exit cleanly.

```javascript
import { createServer } from 'node:http';

const server = createServer(handler);
const connections = new Set();

// Track active connections for forced shutdown
server.on('connection', (conn) => {
  connections.add(conn);
  conn.on('close', () => connections.delete(conn));
});

server.listen(3000, () => console.log('Server running on :3000'));

// Graceful shutdown
async function shutdown(signal) {
  console.log(`${signal} received. Starting graceful shutdown...`);

  // 1. Stop accepting new connections
  server.close(() => {
    console.log('HTTP server closed');
  });

  // 2. Set a deadline for in-flight requests
  const forceShutdownTimer = setTimeout(() => {
    console.error('Forced shutdown — destroying remaining connections');
    connections.forEach(conn => conn.destroy());
    process.exit(1);
  }, 30000); // 30 second deadline
  forceShutdownTimer.unref();

  // 3. Close other resources
  try {
    await Promise.allSettled([
      db.disconnect(),
      redis.quit(),
      messageQueue.close(),
    ]);
    console.log('All resources closed');
  } catch (err) {
    console.error('Error during cleanup:', err);
  }

  process.exit(0);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

// Also handle uncaught errors
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  shutdown('uncaughtException');
});
```

Key steps: 1) Stop accepting new connections, 2) Wait for in-flight requests with a deadline, 3) Close external resources (DB, Redis, queues), 4) Force exit if deadline passes.

Create a reusable worker thread pool to handle CPU-intensive tasks without blocking the event loop.

```javascript
// worker-pool.js
import { Worker } from 'node:worker_threads';
import { cpus } from 'node:os';
import { EventEmitter } from 'node:events';

export class WorkerPool extends EventEmitter {
  #workers = [];
  #queue = [];
  #activeCount = 0;

  constructor(workerPath, poolSize = cpus().length) {
    super();
    this.workerPath = workerPath;
    this.poolSize = poolSize;
  }

  async execute(data) {
    return new Promise((resolve, reject) => {
      const task = { data, resolve, reject };

      if (this.#activeCount < this.poolSize) {
        this.#runTask(task);
      } else {
        this.#queue.push(task);
      }
    });
  }

  #runTask(task) {
    this.#activeCount++;
    const worker = new Worker(this.workerPath, {
      workerData: task.data,
    });

    worker.on('message', (result) => {
      task.resolve(result);
      this.#onWorkerDone();
    });

    worker.on('error', (err) => {
      task.reject(err);
      this.#onWorkerDone();
    });
  }

  #onWorkerDone() {
    this.#activeCount--;
    if (this.#queue.length > 0) {
      this.#runTask(this.#queue.shift());
    }
  }

  get pending() { return this.#queue.length; }
  get active() { return this.#activeCount; }
}

// cpu-worker.js
import { workerData, parentPort } from 'node:worker_threads';

// CPU-intensive computation
function fibonacci(n) {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

const result = fibonacci(workerData.n);
parentPort.postMessage({ result, input: workerData.n });

// main.js — usage
import { WorkerPool } from './worker-pool.js';

const pool = new WorkerPool('./cpu-worker.js', 4);

const results = await Promise.all([
  pool.execute({ n: 40 }),
  pool.execute({ n: 42 }),
  pool.execute({ n: 38 }),
  pool.execute({ n: 41 }),
  pool.execute({ n: 39 }), // Queued — only 4 workers
]);
```

Size the pool to the number of CPU cores. Tasks beyond pool size are queued. Each worker is a separate thread with its own V8 isolate.

Process large files line-by-line or chunk-by-chunk using transform streams and the pipeline API.

```javascript
import { createReadStream, createWriteStream } from 'node:fs';
import { pipeline } from 'node:stream/promises';
import { Transform } from 'node:stream';
import { createInterface } from 'node:readline';

// Transform stream for processing CSV data
class CSVTransform extends Transform {
  constructor(options) {
    super({ ...options, objectMode: true });
    this.lineCount = 0;
  }

  _transform(line, encoding, callback) {
    this.lineCount++;
    if (this.lineCount === 1) {
      callback(); // Skip header
      return;
    }

    const [name, email, age] = line.split(',');
    if (parseInt(age) >= 18) {
      this.push(JSON.stringify({ name, email, age: parseInt(age) }) + '\n');
    }
    callback();
  }
}

// Process a large CSV file
const rl = createInterface({
  input: createReadStream('users.csv'),
  crlfDelay: Infinity,
});

const output = createWriteStream('adults.jsonl');
const transform = new CSVTransform();

// Using async generators with pipeline
await pipeline(
  rl,
  transform,
  output
);

// Alternative: async generator as transform
await pipeline(
  createReadStream('input.txt'),
  async function* (source) {
    for await (const chunk of source) {
      const text = chunk.toString();
      // Transform each chunk
      yield text.toUpperCase();
    }
  },
  createWriteStream('output.txt')
);

// With compression:
import { createGzip, createGunzip } from 'node:zlib';

await pipeline(
  createReadStream('data.jsonl'),
  createGzip(),
  createWriteStream('data.jsonl.gz')
);
```

Use `pipeline()` from `node:stream/promises` for proper error handling and cleanup. Async generators work as inline transform functions.

Structure tests with the built-in Node.js test runner using describe/it blocks, lifecycle hooks, and subtests.

```javascript
import { describe, it, before, after, beforeEach, afterEach, mock } from 'node:test';
import assert from 'node:assert/strict';

describe('UserService', () => {
  let db;
  let service;

  before(async () => {
    // Run once before all tests in this describe block
    db = await createTestDatabase();
    service = new UserService(db);
  });

  after(async () => {
    await db.close();
  });

  beforeEach(async () => {
    await db.clear(); // Clean state for each test
  });

  describe('createUser', () => {
    it('creates a user with valid input', async () => {
      const user = await service.createUser({ name: 'Alice', email: 'a@b.com' });
      assert.equal(user.name, 'Alice');
      assert.match(user.id, /^usr_/);
    });

    it('rejects duplicate emails', async () => {
      await service.createUser({ name: 'Alice', email: 'a@b.com' });
      await assert.rejects(
        () => service.createUser({ name: 'Bob', email: 'a@b.com' }),
        { message: /duplicate email/i }
      );
    });

    it('validates email format', async () => {
      await assert.rejects(
        () => service.createUser({ name: 'Alice', email: 'not-an-email' }),
        { message: /invalid email/i }
      );
    });
  });

  describe('with mocked dependencies', () => {
