      const svc = new UserService(db, { sendEmail });

      await svc.createUser({ name: 'Alice', email: 'a@b.com' });

      assert.equal(sendEmail.mock.callCount(), 1);
      assert.deepEqual(sendEmail.mock.calls[0].arguments[0], {
        to: 'a@b.com',
        template: 'welcome',
      });
    });
  });
});
