Detect and diagnose memory leaks using built-in Node.js tools without external dependencies.

```javascript
import v8 from 'node:v8';
import { writeFileSync } from 'node:fs';

// 1. Monitor heap growth over time
class MemoryMonitor {
  #samples = [];
  #interval;

  start(intervalMs = 10000) {
    this.#interval = setInterval(() => {
      const usage = process.memoryUsage();
      const sample = {
        timestamp: Date.now(),
        heapUsedMB: +(usage.heapUsed / 1024 / 1024).toFixed(1),
        rssMB: +(usage.rss / 1024 / 1024).toFixed(1),
        externalMB: +(usage.external / 1024 / 1024).toFixed(1),
      };
      this.#samples.push(sample);

      // Detect growth trend
      if (this.#samples.length >= 6) {
        const recent = this.#samples.slice(-6);
        const first = recent[0].heapUsedMB;
        const last = recent[recent.length - 1].heapUsedMB;
        const growthRate = ((last - first) / first * 100).toFixed(1);

        if (last > first * 1.5) {
          console.warn(`Memory leak suspected: heap grew ${growthRate}% in last ${6 * intervalMs / 1000}s`);
          this.snapshot();
        }
      }
    }, intervalMs);
    this.#interval.unref();
  }

  snapshot() {
    const filename = v8.writeHeapSnapshot();
    console.log(`Heap snapshot written to: ${filename}`);
    // Open in Chrome DevTools → Memory tab
  }

  stop() {
    clearInterval(this.#interval);
  }
}

// 2. Track EventEmitter listener counts
import { EventEmitter } from 'node:events';

function monitorListeners(emitter, name) {
  const original = emitter.on.bind(emitter);
