Use the cluster module with sticky sessions for WebSocket support and zero-downtime rolling restarts.

```javascript
import cluster from 'node:cluster';
import { cpus } from 'node:os';
import net from 'node:net';
import { createHash } from 'node:crypto';

if (cluster.isPrimary) {
  const numWorkers = cpus().length;
  const workers = [];

  // Fork workers
  for (let i = 0; i < numWorkers; i++) {
    workers.push(cluster.fork());
  }

  // Sticky session: route by source IP
  const server = net.createServer({ pauseOnConnect: true }, (conn) => {
    const hash = createHash('md5')
      .update(conn.remoteAddress || '')
      .digest();
    const workerIndex = hash.readUInt32BE(0) % workers.length;
    workers[workerIndex].send('sticky-session:connection', conn);
  });

  server.listen(3000);

  // Zero-downtime restart
  process.on('SIGUSR2', () => {
    console.log('Rolling restart initiated');
    let i = 0;
    const restart = () => {
      if (i >= workers.length) return;
      const worker = workers[i];
      console.log(`Restarting worker ${worker.process.pid}`);

      const replacement = cluster.fork();
      replacement.on('listening', () => {
        worker.disconnect();
        workers[i] = replacement;
        i++;
        setTimeout(restart, 1000); // Stagger restarts
      });
    };
    restart();
  });

  // Auto-restart crashed workers
  cluster.on('exit', (worker, code) => {
    if (code !== 0) {
      console.log(`Worker ${worker.process.pid} crashed. Restarting...`);
      const idx = workers.indexOf(worker);
      workers[idx] = cluster.fork();
    }
  });
} else {
  // Worker process
  const app = createApp(); // Your Express/Fastify app

  // Receive connections from primary
  process.on('message', (msg, conn) => {
    if (msg === 'sticky-session:connection') {
      app.emit('connection', conn);
      conn.resume();
    }
  });
}
```

Send `SIGUSR2` to the primary process for zero-downtime restart. Each worker restarts one at a time with a delay. Sticky sessions ensure WebSocket connections always reach the same worker.

Create a custom ESM loader in Node.js 22 to intercept and transform module imports.

```javascript
// loader.mjs — custom loader
export async function resolve(specifier, context, nextResolve) {
  // Alias: @/ → ./src/
  if (specifier.startsWith('@/')) {
    const newSpecifier = specifier.replace('@/', './src/');
    return nextResolve(newSpecifier, context);
  }

  // Block specific imports (e.g., in tests)
  if (specifier.includes('production-only-module')) {
    throw new Error(`Import of '${specifier}' is blocked in this context`);
  }

  return nextResolve(specifier, context);
}

export async function load(url, context, nextLoad) {
  // Transform .env files into JS modules
  if (url.endsWith('.env')) {
    const source = await readFile(new URL(url), 'utf-8');
    const vars = source.split('\n')
      .filter(line => line && !line.startsWith('#'))
      .map(line => {
        const [key, ...vals] = line.split('=');
        return `export const ${key.trim()} = ${JSON.stringify(vals.join('=').trim())};`;
      })
      .join('\n');

    return { format: 'module', source: vars, shortCircuit: true };
  }

  return nextLoad(url, context);
}
```

