Implement structured JSON logging for production services without external dependencies.

```javascript
// logger.js
const LOG_LEVELS = { debug: 0, info: 1, warn: 2, error: 3 };
const MIN_LEVEL = LOG_LEVELS[process.env.LOG_LEVEL || 'info'];

function createLogger(context = {}) {
  function log(level, message, data = {}) {
    if (LOG_LEVELS[level] < MIN_LEVEL) return;

    const entry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      ...context,
      ...data,
    };

    // Serialize errors properly
    if (data.error instanceof Error) {
      entry.error = {
        name: data.error.name,
        message: data.error.message,
        stack: data.error.stack,
        ...(data.error.code ? { code: data.error.code } : {}),
      };
    }

    const output = JSON.stringify(entry);
    if (level === 'error' || level === 'warn') {
      process.stderr.write(output + '\n');
    } else {
      process.stdout.write(output + '\n');
    }
  }

  return {
    debug: (msg, data) => log('debug', msg, data),
    info: (msg, data) => log('info', msg, data),
    warn: (msg, data) => log('warn', msg, data),
    error: (msg, data) => log('error', msg, data),
    child: (childContext) => createLogger({ ...context, ...childContext }),
  };
}

export const logger = createLogger({ service: 'my-api', version: '1.0.0' });

// Usage
logger.info('Server started', { port: 3000 });
// {"timestamp":"2024-...","level":"info","message":"Server started","service":"my-api","version":"1.0.0","port":3000}

// Child logger with request context
function handleRequest(req, res) {
  const reqLogger = logger.child({
    requestId: req.headers['x-request-id'],
    method: req.method,
    path: req.url,
  });

  reqLogger.info('Request received');
  // {"timestamp":"...","level":"info","message":"Request received","service":"my-api","requestId":"abc-123","method":"GET","path":"/users"}

  try {
    // ... handle request
  } catch (err) {
    reqLogger.error('Request failed', { error: err, statusCode: 500 });
  }
}
```

Structured JSON logging enables parsing by log aggregators (CloudWatch, Datadog, ELK). Use `process.stdout.write` not `console.log` to avoid extra newlines and formatting.

Watch files for changes with proper debouncing to avoid duplicate events and handle common gotchas.

```javascript
import { watch } from 'node:fs';
import { readFile, stat } from 'node:fs/promises';
import { join, extname } from 'node:path';

class FileWatcher {
  #watchers = new Map();
  #debounceTimers = new Map();
  #debounceMs;

  constructor(debounceMs = 100) {
    this.#debounceMs = debounceMs;
  }

  watch(dir, callback, options = {}) {
    const { extensions = [], recursive = true, ignore = [] } = options;

    // GOTCHA: fs.watch fires multiple events for a single file change
    // Must debounce by filename
    const watcher = watch(dir, { recursive }, (eventType, filename) => {
      if (!filename) return;
      if (extensions.length && !extensions.includes(extname(filename))) return;
      if (ignore.some(pattern => filename.includes(pattern))) return;

      // Debounce: only fire once per file per interval
      const key = `${dir}:${filename}`;
      clearTimeout(this.#debounceTimers.get(key));
      this.#debounceTimers.set(key, setTimeout(async () => {
        try {
          const fullPath = join(dir, filename);
          const stats = await stat(fullPath).catch(() => null);
          if (!stats) return; // File was deleted

          callback({
            event: eventType,
            filename,
            fullPath,
            size: stats.size,
            modified: stats.mtime,
          });
        } catch (err) {
          if (err.code !== 'ENOENT') console.error('Watch error:', err);
        }
      }, this.#debounceMs));
    });

    this.#watchers.set(dir, watcher);
    return () => this.unwatch(dir);
  }

  unwatch(dir) {
    this.#watchers.get(dir)?.close();
    this.#watchers.delete(dir);
  }

  close() {
    for (const [dir] of this.#watchers) this.unwatch(dir);
    for (const timer of this.#debounceTimers.values()) clearTimeout(timer);
  }
}

// Usage
const watcher = new FileWatcher(200);

watcher.watch('./src', (change) => {
  console.log(`${change.event}: ${change.filename}`);
}, {
  extensions: ['.js', '.ts', '.json'],
  ignore: ['node_modules', '.git', 'dist'],
});

// Cleanup on exit
process.on('SIGINT', () => { watcher.close(); process.exit(0); });
```

`fs.watch` fires duplicate events — always debounce. Use `recursive: true` for watching subdirectories. Filter by extension and ignore patterns to reduce noise.

Load configuration from multiple sources with environment-specific overrides, validation, and type safety.

```javascript
import { readFileSync, existsSync } from 'node:fs';
import { join } from 'node:path';

function loadConfig(options = {}) {
  const env = process.env.NODE_ENV || 'development';
  const configDir = options.configDir || join(import.meta.dirname, '..', 'config');

  // 1. Load base config
  const base = loadJSON(join(configDir, 'default.json'));

  // 2. Load environment-specific config
  const envConfig = loadJSON(join(configDir, `${env}.json`));

  // 3. Load local overrides (git-ignored)
  const local = loadJSON(join(configDir, 'local.json'));

  // 4. Deep merge: base < env < local < env vars
  const config = deepMerge(deepMerge(deepMerge(base, envConfig), local), envOverrides());

  // 5. Validate required fields
  const required = ['server.port', 'database.url', 'jwt.secret'];
  for (const key of required) {
    if (getNestedValue(config, key) === undefined) {
      throw new Error(`Missing required config: ${key}`);
    }
  }

  // 6. Freeze to prevent mutation
  return Object.freeze(config);
}

function loadJSON(path) {
  if (!existsSync(path)) return {};
  return JSON.parse(readFileSync(path, 'utf-8'));
}

// Map APP_ prefixed env vars to config
function envOverrides() {
  const overrides = {};
  for (const [key, value] of Object.entries(process.env)) {
    if (key.startsWith('APP_')) {
      // APP_SERVER_PORT → server.port
      const configKey = key.slice(4).toLowerCase().replace(/_/g, '.');
      setNestedValue(overrides, configKey, coerce(value));
    }
  }
  return overrides;
}

function coerce(value) {
  if (value === 'true') return true;
  if (value === 'false') return false;
  if (/^\d+$/.test(value)) return parseInt(value, 10);
  return value;
}

// Usage
export const config = loadConfig();
// config.server.port — number
// config.database.url — string
```

Config precedence: default.json < {env}.json < local.json < environment variables. The `local.json` file is git-ignored for developer-specific settings.

Implement comprehensive health checks that verify all dependencies, suitable for Kubernetes probes and load balancers.

```javascript
import { createServer } from 'node:http';

const healthChecks = {
  async database() {
    const start = Date.now();
    await db.query('SELECT 1');
    return { status: 'ok', latencyMs: Date.now() - start };
  },
  async redis() {
    const start = Date.now();
    await redis.ping();
    return { status: 'ok', latencyMs: Date.now() - start };
  },
  async diskSpace() {
    const { execSync } = await import('node:child_process');
    const output = execSync('df -h / | tail -1').toString();
    const usedPercent = parseInt(output.split(/\s+/)[4]);
    return {
      status: usedPercent < 90 ? 'ok' : 'degraded',
      usedPercent,
    };
  },
  memory() {
    const usage = process.memoryUsage();
    const heapUsedMB = usage.heapUsed / 1024 / 1024;
    return {
      status: heapUsedMB < 512 ? 'ok' : 'degraded',
      heapUsedMB: +heapUsedMB.toFixed(1),
      rssMB: +(usage.rss / 1024 / 1024).toFixed(1),
    };
  },
};

async function runHealthChecks() {
  const results = {};
  let overall = 'ok';

  await Promise.allSettled(
    Object.entries(healthChecks).map(async ([name, check]) => {
      try {
        results[name] = await Promise.race([
          check(),
          new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), 5000)),
        ]);
      } catch (err) {
        results[name] = { status: 'error', message: err.message };
        overall = 'error';
      }
    })
  );

  if (Object.values(results).some(r => r.status === 'degraded')) {
    overall = overall === 'error' ? 'error' : 'degraded';
  }

  return {
    status: overall,
    uptime: process.uptime(),
    timestamp: new Date().toISOString(),
    checks: results,
  };
}

// Kubernetes-style endpoints
// /healthz — liveness (is the process alive?)
// /readyz  — readiness (can it handle traffic?)
app.get('/healthz', (req, res) => {
  res.status(200).json({ status: 'ok' });
});

app.get('/readyz', async (req, res) => {
  const health = await runHealthChecks();
  const status = health.status === 'ok' ? 200 : 503;
  res.status(status).json(health);
});
```

Separate liveness (`/healthz` — always 200 if process is running) from readiness (`/readyz` — checks dependencies). Add timeouts to prevent health checks from hanging.

