`AsyncLocalStorage` is the Node.js equivalent of Java's ThreadLocal. It works across `await`, callbacks, `setTimeout`, and event emitters without manual propagation.

Implement a token bucket rate limiter for HTTP APIs using only Node.js built-ins.

```javascript
class TokenBucket {
  #tokens;
  #maxTokens;
  #refillRate; // tokens per millisecond
  #lastRefill;

  constructor(maxTokens, refillPerSecond) {
    this.#tokens = maxTokens;
    this.#maxTokens = maxTokens;
    this.#refillRate = refillPerSecond / 1000;
    this.#lastRefill = Date.now();
  }

  consume(tokens = 1) {
    this.#refill();
    if (this.#tokens >= tokens) {
      this.#tokens -= tokens;
      return { allowed: true, remaining: Math.floor(this.#tokens) };
    }
    return {
      allowed: false,
      remaining: 0,
      retryAfterMs: Math.ceil((tokens - this.#tokens) / this.#refillRate),
    };
  }

  #refill() {
    const now = Date.now();
    const elapsed = now - this.#lastRefill;
    this.#tokens = Math.min(this.#maxTokens, this.#tokens + elapsed * this.#refillRate);
    this.#lastRefill = now;
  }
}

// Per-client rate limiting
const buckets = new Map();

function getRateLimiter(clientId) {
  if (!buckets.has(clientId)) {
    buckets.set(clientId, new TokenBucket(100, 10)); // 100 burst, 10/sec sustained
  }
  return buckets.get(clientId);
}

// Clean up old buckets periodically
setInterval(() => {
  const cutoff = Date.now() - 60000;
  for (const [key, bucket] of buckets) {
    if (bucket.lastUsed < cutoff) buckets.delete(key);
  }
}, 60000).unref();

// Express middleware
function rateLimitMiddleware(req, res, next) {
  const clientId = req.ip || req.headers['x-forwarded-for'] || 'unknown';
  const limiter = getRateLimiter(clientId);
  const result = limiter.consume();

  res.setHeader('X-RateLimit-Remaining', result.remaining);

  if (!result.allowed) {
    res.setHeader('Retry-After', Math.ceil(result.retryAfterMs / 1000));
    return res.status(429).json({
      error: 'Too Many Requests',
      retryAfterMs: result.retryAfterMs,
    });
  }

  next();
}

app.use(rateLimitMiddleware);
```

Token bucket allows bursts while enforcing a sustained rate. For distributed systems, replace the in-memory Map with Redis using `MULTI/EXEC` for atomic operations.

Spawn child processes with proper error handling, stdio streaming, and timeout management.

```javascript
import { spawn } from 'node:child_process';

function exec(command, args, options = {}) {
  const { timeout = 30000, cwd, env, onStdout, onStderr } = options;

  return new Promise((resolve, reject) => {
    const child = spawn(command, args, {
      cwd,
      env: { ...process.env, ...env },
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    let stdout = '';
    let stderr = '';
    let killed = false;

    // Timeout
    const timer = setTimeout(() => {
      killed = true;
      child.kill('SIGTERM');
      setTimeout(() => {
        if (!child.killed) child.kill('SIGKILL');
      }, 5000);
    }, timeout);

    child.stdout.on('data', (chunk) => {
      const text = chunk.toString();
      stdout += text;
      onStdout?.(text);
    });

    child.stderr.on('data', (chunk) => {
      const text = chunk.toString();
      stderr += text;
      onStderr?.(text);
    });

    child.on('error', (err) => {
      clearTimeout(timer);
      reject(new Error(`Failed to spawn '${command}': ${err.message}`));
    });

    child.on('close', (code, signal) => {
      clearTimeout(timer);
      if (killed) {
        reject(new Error(`Process timed out after ${timeout}ms`));
      } else if (code !== 0) {
        const err = new Error(`Process exited with code ${code}: ${stderr.trim()}`);
        err.code = code;
        err.stderr = stderr;
        err.stdout = stdout;
        reject(err);
      } else {
        resolve({ stdout, stderr, code });
      }
    });
  });
}

// Usage
try {
  const { stdout } = await exec('git', ['log', '--oneline', '-10'], {
    cwd: '/path/to/repo',
    timeout: 5000,
    onStdout: (line) => process.stdout.write(line), // Stream output
  });
  console.log('Git log:', stdout);
} catch (err) {
  console.error('Git failed:', err.message);
  console.error('stderr:', err.stderr);
}

// Run multiple commands in sequence
async function runPipeline(commands) {
  const results = [];
  for (const { cmd, args, ...opts } of commands) {
    results.push(await exec(cmd, args, opts));
  }
  return results;
}
```

Always use `spawn` with args array (not `exec` with string) to avoid shell injection. Add timeouts with SIGTERM fallback to SIGKILL. Stream stdout/stderr for real-time output.

