Process files in parallel across worker threads with shared progress tracking.

```javascript
// main.js
import { Worker } from 'node:worker_threads';
import { readdir } from 'node:fs/promises';
import { join } from 'node:path';
import { cpus } from 'node:os';

async function processFilesParallel(dir, workerPath) {
  const files = (await readdir(dir))
    .filter(f => f.endsWith('.json'))
    .map(f => join(dir, f));

  // Shared progress counter
  const progress = new SharedArrayBuffer(4);
  const progressView = new Int32Array(progress);

  const numWorkers = Math.min(cpus().length, files.length);
  const chunkSize = Math.ceil(files.length / numWorkers);

  const workerPromises = Array.from({ length: numWorkers }, (_, i) => {
    const chunk = files.slice(i * chunkSize, (i + 1) * chunkSize);
    return new Promise((resolve, reject) => {
      const worker = new Worker(workerPath, {
        workerData: { files: chunk, progress },
      });
      worker.on('message', resolve);
      worker.on('error', reject);
    });
  });

  // Progress reporter
  const progressInterval = setInterval(() => {
    const done = Atomics.load(progressView, 0);
    const pct = ((done / files.length) * 100).toFixed(1);
    process.stdout.write(`\rProgress: ${done}/${files.length} (${pct}%)`);
  }, 100);

  const results = await Promise.all(workerPromises);
  clearInterval(progressInterval);
  console.log('\nDone!');

  return results.flat();
}

// file-worker.js
import { workerData, parentPort } from 'node:worker_threads';
import { readFile } from 'node:fs/promises';

const { files, progress } = workerData;
const progressView = new Int32Array(progress);
const results = [];

for (const file of files) {
  const content = JSON.parse(await readFile(file, 'utf-8'));
  // Process file...
  results.push({ file, recordCount: content.length });
  Atomics.add(progressView, 0, 1); // Atomic increment
}

parentPort.postMessage(results);
```

Use `SharedArrayBuffer` with `Atomics` for lock-free progress tracking across threads. Split work evenly across workers matching CPU core count.

Stream large JSON datasets to clients without buffering the entire response in memory.

```javascript
import { createServer } from 'node:http';

const server = createServer(async (req, res) => {
  if (req.url === '/api/users/stream') {
    res.writeHead(200, {
      'Content-Type': 'application/json',
      'Transfer-Encoding': 'chunked',
    });

    // Stream a large JSON array
    res.write('[\n');
    let first = true;

    const cursor = db.users.find().cursor();
    for await (const user of cursor) {
      if (!first) res.write(',\n');
      first = false;
      res.write(JSON.stringify(user));
